: 24-52 lines are duplicate of `test/e2e/flows/minio/client.go:86-114`
Category: dupl
File: test/e2e/flows/minio/client.go
Line: 24
Details: func (c *Client) UploadImage(t *testing.T, token string, filename string, content []byte) *http.Response {
	body := &bytes.Buffer{}
	writer := multipart.NewWriter(body)

	h := make(http.Header)
	h.Set("Content-Disposition", fmt.Sprintf(`form-data; name="file"; filename="%s"`, filename))
	h.Set("Content-Type", "image/jpeg")
	part, err := writer.CreatePart(textproto.MIMEHeader(h))
	if err != nil {
		t.Fatal(err)
	}
	part.Write(content)
	writer.Close()

	req, err := http.NewRequest(http.MethodPost, c.endpoint+"/api/v1/files/upload/image", body)
	if err != nil {
		t.Fatal(err)
	}
	req.Header.Set("Content-Type", writer.FormDataContentType())
	if token != "" {
		req.Header.Set("Authorization", "Bearer "+token)
	}

	resp, err := c.client.Do(req)
	if err != nil {
		t.Fatal(err)
	}
	return resp
}

